import{_ as i,o as l,c as t,a2 as e}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"Form 表单","description":"","frontmatter":{"title":"Form 表单","stage":"intermediate","direction":"interaction-design","tags":["interaction-pattern","input","form"]},"headers":[],"relativePath":"03-interaction-design/notes/interaction-patterns/input/form.md","filePath":"03-interaction-design/notes/interaction-patterns/input/form.md","lastUpdated":1784382331000}'),s={name:"03-interaction-design/notes/interaction-patterns/input/form.md"};function n(r,a,h,o,d,p){return l(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="form-表单" tabindex="-1">Form 表单 <a class="header-anchor" href="#form-表单" aria-label="Permalink to &quot;Form 表单&quot;">​</a></h1><p>Form 表单把一组相互关联的字段转换为一次可验证的业务提交。字段依赖、错误归属、提交原子性和草稿边界决定它是一张表单还是多个独立任务。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>Form 表单负责把用户输入转换为可校验、可提交、可恢复的数据。它不能替代服务端授权、业务校验、唯一约束、恶意内容处理或并发控制。</p><p>前置知识：</p><ul><li>能定义字段或文档的数据类型、必填、范围和业务不变量；</li><li>能区分原始输入、显示值、规范化值和稳定对象 ID；</li><li>了解表单标签、可访问名称、焦点顺序和状态消息；</li><li>能观察请求、响应、对象版本和权威写入结果。</li></ul><h2 id="组成部分" tabindex="-1">组成部分 <a class="header-anchor" href="#组成部分" aria-label="Permalink to &quot;组成部分&quot;">​</a></h2><ul><li>标签：可见、唯一并与控件程序化关联。</li><li>帮助：在输入前说明格式、单位和限制。</li><li>分组：fieldset/legend 表达一组相关选项。</li><li>校验：客户端即时反馈与服务端权威校验分层。</li><li>提交：明确主动作、等待、结果、错误摘要和输入保留。</li></ul><p>标签、帮助、分组和错误都应指向同一个稳定字段 ID；提交合同还要说明跨字段规则、服务端错误路径和部分字段能否回显。这样错误摘要才能准确跳到控件，后端也能把拒绝原因映射回用户正在修改的字段。</p><h2 id="输入数据生命周期" tabindex="-1">输入数据生命周期 <a class="header-anchor" href="#输入数据生命周期" aria-label="Permalink to &quot;输入数据生命周期&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R[&quot;原始输入&quot;] --&gt; C[&quot;客户端可快速检查&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; N[&quot;规范化或对象选择&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    N --&gt; D[&quot;本地草稿&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; S[&quot;服务端授权与业务校验&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; W[&quot;受控写入&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    W --&gt; E[&quot;结果、版本与审计&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; F[&quot;字段、全局、冲突或临时错误&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; D</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="原始输入" tabindex="-1">原始输入 <a class="header-anchor" href="#原始输入" aria-label="Permalink to &quot;原始输入&quot;">​</a></h3><p>每个字段分别保存用户输入值和最近一次已确认值。税号、地址、姓名等字段不能因为客户端习惯性 trim 或改写大小写而丢失可核对内容；只有字段合同声明等价规则时才转换。</p><h3 id="规范化值" tabindex="-1">规范化值 <a class="header-anchor" href="#规范化值" aria-label="Permalink to &quot;规范化值&quot;">​</a></h3><p>规范化按字段执行：枚举提交枚举码，实体选择提交对象 ID，金额提交币种与最小货币单位，日期提交约定日历和时区语义。跨字段校验使用规范化候选对象，但错误仍关联原始字段和值。</p><h3 id="草稿" tabindex="-1">草稿 <a class="header-anchor" href="#草稿" aria-label="Permalink to &quot;草稿&quot;">​</a></h3><p>草稿策略按字段分类，而不是整表一刀切。普通说明可进入服务端草稿，密码、一次性验证码和完整支付凭据不得持久化；恢复草稿时要携带基础对象版本，避免旧草稿覆盖已更新资料。</p><h3 id="权威结果" tabindex="-1">权威结果 <a class="header-anchor" href="#权威结果" aria-label="Permalink to &quot;权威结果&quot;">​</a></h3><p>创建或更新成功后，以响应中的资源 ID、版本和服务端规范化值刷新查看态。若提交只启动审核或导入任务，表单进入“已接收、处理中”，使用任务 ID 跟踪，不能提前清空为已完成。</p><h2 id="专属行为" tabindex="-1">专属行为 <a class="header-anchor" href="#专属行为" aria-label="Permalink to &quot;专属行为&quot;">​</a></h2><ul><li>不要用 placeholder 替代标签；占位文本会消失且不是稳定名称。</li><li>必填、格式和范围同时通过语义与文字表达。</li><li>错误摘要链接到字段，字段旁保留具体错误和原值。</li><li>浏览器自动填充使用正确 autocomplete token，不阻止粘贴。</li><li>提交响应返回字段错误、全局错误、版本冲突和未知结果的稳定结构。</li></ul><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><ol><li>单页分组还是多步骤，依据依赖和检查成本。</li><li>何时校验，避免用户尚未完成输入就持续报错。</li><li>默认值是否代表安全常见选择，还是会造成无意识同意。</li><li>敏感字段是否允许草稿、本地持久化或分析采集。</li><li>服务端拒绝后哪些字段可安全回显。</li></ol><p>验收要逐项证明字段依赖、默认值、校验时机、敏感草稿和错误回显符合合同，并覆盖客户端通过而服务端按跨字段规则拒绝的路径。</p><h2 id="状态模型" tabindex="-1">状态模型 <a class="header-anchor" href="#状态模型" aria-label="Permalink to &quot;状态模型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>进入条件</th><th>界面责任</th><th>退出条件</th></tr></thead><tbody><tr><td>Form 表单未触碰</td><td>还没有本次交互</td><td>显示标签、规则和合理默认值</td><td>用户输入或选择</td></tr><tr><td>编辑中</td><td>原始值正在变化</td><td>保持焦点和输入法行为</td><td>完成输入、取消或提交</td></tr><tr><td>本地无效</td><td>可确定格式或范围错误</td><td>就近说明修正方式</td><td>输入变为有效</td></tr><tr><td>可提交</td><td>本地条件满足</td><td>主操作可用，不承诺业务成功</td><td>提交、继续编辑</td></tr><tr><td>提交中</td><td>请求或上传进行</td><td>防重复意图，保留输入</td><td>成功、失败、超时、取消</td></tr><tr><td>服务端拒绝</td><td>字段或跨字段规则不满足</td><td>错误摘要链接到字段；无法归属的错误放在表单级</td><td>修正对应字段或返回</td></tr><tr><td>冲突</td><td>基础对象版本变化</td><td>比较、刷新或合并</td><td>新版本确认</td></tr><tr><td>提交结果未知</td><td>请求超时且可能已经创建对象</td><td>禁止盲目重复，按幂等键查询提交结果</td><td>找到资源、确认失败或人工处理</td></tr><tr><td>成功</td><td>权威结果完成</td><td>显示结果和下一步</td><td>后续操作</td></tr></tbody></table><p>状态不能只存在于颜色。错误、等待、选中、进度和保存结果应有程序化表达。</p><h2 id="工程状态示例" tabindex="-1">工程状态示例 <a class="header-anchor" href="#工程状态示例" aria-label="Permalink to &quot;工程状态示例&quot;">​</a></h2><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;rawValue&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;normalizedValue&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;errors&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;dirty&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>示例字段不是通用接口标准。项目应按Form 表单的真实值类型定义 schema，并明确缺失值、无效值、服务端错误、版本和恢复语义。</p><h2 id="校验顺序" tabindex="-1">校验顺序 <a class="header-anchor" href="#校验顺序" aria-label="Permalink to &quot;校验顺序&quot;">​</a></h2><ol><li>Form 表单输入前说明格式、单位、范围和不可接受内容。</li><li>输入期间只做不会打断输入法的安全检查。</li><li>完成输入或离开字段后给出可修正反馈。</li><li>提交时客户端汇总当前已知错误。</li><li>服务端重新执行格式、授权、业务和并发校验。</li><li>返回字段错误与全局错误的稳定代码和安全文案。</li><li>界面保留合法输入，把焦点移到合理错误入口。</li><li>修正后只清除已经解决的错误。</li><li>成功后从权威响应更新对象和版本。</li></ol><p>客户端限制可以减少错误，不能防止直接请求、旧客户端或恶意输入。</p><h2 id="案例一-企业创建成员并分配角色" tabindex="-1">案例一：企业创建成员并分配角色 <a class="header-anchor" href="#案例一-企业创建成员并分配角色" aria-label="Permalink to &quot;案例一：企业创建成员并分配角色&quot;">​</a></h2><h3 id="固定输入" tabindex="-1">固定输入 <a class="header-anchor" href="#固定输入" aria-label="Permalink to &quot;固定输入&quot;">​</a></h3><ul><li>使用合成账户与合成业务数据；</li><li>正常网络 80 ms，另注入 2 秒延迟和一次 503；</li><li>打开时对象版本为 17，提交前另一个会话更新为 18；</li><li>覆盖空值、无效值、长值、重复值和权限撤销；</li><li>记录可见结果、焦点、请求、响应和权威对象。</li></ul><h3 id="设计与实现" tabindex="-1">设计与实现 <a class="header-anchor" href="#设计与实现" aria-label="Permalink to &quot;设计与实现&quot;">​</a></h3><ol><li>不要用 placeholder 替代标签；占位文本会消失且不是稳定名称。</li><li>必填、格式和范围同时通过语义与文字表达。</li><li>错误摘要链接到字段，字段旁保留具体错误和原值。</li><li>浏览器自动填充使用正确 autocomplete token，不阻止粘贴。</li><li>提交响应返回字段错误、全局错误、版本冲突和未知结果的稳定结构。</li></ol><p>服务端成功响应返回客户对象 ID、规范化后的税务地址和新版本；页面用这些值替换草稿，并把服务端未接受的显示差异明确呈现，不能直接回显提交对象冒充保存结果。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>鼠标、键盘、触屏和屏幕阅读器都能完成；</li><li>输入法组合期间不误提交；</li><li>本地错误与服务端错误均能修正；</li><li>请求失败和冲突不清空合法工作；</li><li>重复触发只产生一个逻辑副作用；</li><li>最终显示与权威数据对账一致。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>客户端通过但服务端拒绝后清空全部输入</p><p>修复后重复相同输入和时序，确认界面状态、服务端副作用和审计记录同时正确。</p><h2 id="案例二-用户更新结算资料和税务地址" tabindex="-1">案例二：用户更新结算资料和税务地址 <a class="header-anchor" href="#案例二-用户更新结算资料和税务地址" aria-label="Permalink to &quot;案例二：用户更新结算资料和税务地址&quot;">​</a></h2><h3 id="固定输入-1" tabindex="-1">固定输入 <a class="header-anchor" href="#固定输入-1" aria-label="Permalink to &quot;固定输入&quot;">​</a></h3><ul><li>360 CSS px 视口与 200% 文本缩放；</li><li>系统大字体、中文输入法和仅键盘操作；</li><li>网络先离线，恢复后响应超时；</li><li>会话在未提交工作存在时到期；</li><li>数据包含同名对象、过期引用和被删除目标。</li></ul><h3 id="设计过程" tabindex="-1">设计过程 <a class="header-anchor" href="#设计过程" aria-label="Permalink to &quot;设计过程&quot;">​</a></h3><ol><li>将结算资料按公司身份、地址、税务和联系人分组。</li><li>使用可见 label、fieldset 和 legend 建立语义关系。</li><li>输入完成后执行本地格式检查，提交后接收服务端字段与全局错误。</li><li>错误摘要链接到具体字段，字段保留原值和就近错误。</li><li>服务端拒绝税号重复时保留其他合法字段并允许修正。</li><li>成功后使用返回的客户版本更新页面。</li></ol><p>结算资料在窄屏按公司身份、税务、地址、联系人依次排列，错误紧跟对应字段，错误摘要保持在提交按钮之前。离线期间只标记“本机未提交”，认证恢复后重新取得客户版本再开放保存。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>关闭和恢复网络后不重复写入；</li><li>刷新后按声明的草稿策略恢复；</li><li>会话到期不把敏感值写入不安全存储；</li><li>失效引用有替换、清除或返回路径；</li><li>读屏能获知结果而无需焦点被强制移动；</li><li>长文本不会遮挡唯一保存或取消动作。</li></ul><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>会话在Form 表单进行中到期。界面必须暂停后续写入，保留允许保留的非敏感工作，重新认证后再次校验权限与版本；不能直接重放旧请求。</p><p>会话到期后，税号和联系人草稿是否保留按字段分类执行；重新认证成功后重新读取客户版本，逐项标出仍可提交、因权限变为只读和需要重新输入的敏感字段。</p><h2 id="无障碍实现" tabindex="-1">无障碍实现 <a class="header-anchor" href="#无障碍实现" aria-label="Permalink to &quot;无障碍实现&quot;">​</a></h2><h3 id="名称与说明" tabindex="-1">名称与说明 <a class="header-anchor" href="#名称与说明" aria-label="Permalink to &quot;名称与说明&quot;">​</a></h3><ul><li>Form 表单的可见标签进入可访问名称。</li><li>帮助文本与错误通过程序化关系关联。</li><li>placeholder 不替代持久可见标签。</li><li>必填、单位、格式和限制不只靠颜色或图标。</li><li>复合输入使用与真实行为匹配的 APG 模式。</li></ul><h3 id="键盘与输入法" tabindex="-1">键盘与输入法 <a class="header-anchor" href="#键盘与输入法" aria-label="Permalink to &quot;键盘与输入法&quot;">​</a></h3><ul><li>Form 表单的 Tab 顺序跟随 DOM 与视觉阅读顺序。</li><li>Enter、Space、方向键和 Escape 只按控件语义接管。</li><li>输入法 composition 期间不把中间文本当成完成值。</li><li>粘贴、语音输入和浏览器自动填充不被无理由阻止。</li><li>临时弹层关闭后焦点回到触发点或下一逻辑位置。</li><li>错误修正后焦点不被异步结果抢走。</li></ul><h3 id="重排" tabindex="-1">重排 <a class="header-anchor" href="#重排" aria-label="Permalink to &quot;重排&quot;">​</a></h3><p>在 320 CSS px 等效宽度和 200% 缩放下，fieldset、legend、字段、帮助和错误保持 DOM 顺序；并排地址字段改为纵向排列，提交与错误摘要不能被固定页脚遮挡。</p><h2 id="安全、性能与一致性" tabindex="-1">安全、性能与一致性 <a class="header-anchor" href="#安全、性能与一致性" aria-label="Permalink to &quot;安全、性能与一致性&quot;">​</a></h2><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><ul><li>所有输入均视为不可信；</li><li>服务端重新授权和校验；</li><li>富文本与文件按输出上下文净化或隔离；</li><li>错误不泄露内部异常、受限对象或敏感路径；</li><li>日志不默认记录正文、文件内容、密码或令牌。</li></ul><h3 id="性能" tabindex="-1">性能 <a class="header-anchor" href="#性能" aria-label="Permalink to &quot;性能&quot;">​</a></h3><ul><li>取消失效查询并丢弃乱序响应；</li><li>长列表、长文档和大文件使用适合的分页、分片或后台任务；</li><li>加载优化不改变可访问树的完整语义；</li><li>缓存键包含租户、角色、语言和会改变结果的筛选条件；</li><li>性能预算覆盖输入响应、候选出现、提交和恢复。</li></ul><h3 id="一致性" tabindex="-1">一致性 <a class="header-anchor" href="#一致性" aria-label="Permalink to &quot;一致性&quot;">​</a></h3><ul><li>写请求带幂等或逻辑意图标识；</li><li>对现有对象修改带期望版本；</li><li>超时先查询结果而不是盲目重试；</li><li>部分成功返回逐项稳定 ID 与结果；</li><li>草稿与正式提交使用不同状态和权限；</li><li>客户端缓存不能静默覆盖服务端新版本。</li></ul><h2 id="调试与观测" tabindex="-1">调试与观测 <a class="header-anchor" href="#调试与观测" aria-label="Permalink to &quot;调试与观测&quot;">​</a></h2><ol><li>固定Form 表单的输入、角色、对象版本、网络、语言和视口。</li><li>检查原始值、显示值、选择 ID、错误和焦点。</li><li>检查请求参数、取消、响应顺序和业务错误码。</li><li>检查服务端授权、规范化、版本和权威写入。</li><li>注入超时、权限撤销、并发和页面刷新。</li><li>用键盘、读屏、输入法和窄屏重复。</li></ol><p>观测指标：</p><ul><li>有效开始、提交、成功、失败、取消和恢复；</li><li>首次错误类型与最终修正率；</li><li>输入丢失和重复副作用；</li><li>候选或校验响应延迟；</li><li>键盘阻断、焦点丢失和错误未关联；</li><li>按平台、语言、角色和数据量分群的完成时间。</li></ul><h2 id="综合练习" tabindex="-1">综合练习 <a class="header-anchor" href="#综合练习" aria-label="Permalink to &quot;综合练习&quot;">​</a></h2><p>为Form 表单完成可运行原型和服务端模拟。覆盖正常、无效、等待、失败、权限、过期、冲突、取消和未知结果。</p><p>验收：</p><ul><li>Form 表单的数据类型、显示值、提交值和稳定 ID 边界明确；</li><li>两个案例有固定输入、处理、结果、验证和失败；</li><li>客户端与服务端校验责任分开；</li><li>失败后保留允许保留的工作；</li><li>键盘、屏幕阅读器和输入法完成任务；</li><li>弱网、窄屏和长文本不隐藏恢复；</li><li>日志与分析不收集不必要敏感内容；</li><li>权威数据与界面结果可以对账。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://html.spec.whatwg.org/multipage/forms.html" target="_blank" rel="noreferrer">WHATWG — Forms</a>（访问日期：2026-07-18）</li><li><a href="https://design-system.service.gov.uk/patterns/validation/" target="_blank" rel="noreferrer">GOV.UK Design System — Form validation</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/TR/WCAG22/" target="_blank" rel="noreferrer">W3C — Web Content Accessibility Guidelines (WCAG) 2.2</a>（访问日期：2026-07-18）</li></ul>`,79)])])}const b=i(s,[["render",n]]);export{c as __pageData,b as default};
